        }
    }
}

static class E2
{
    extension(object o)
    {
        public int this[long l, int i]
        {
            get => throw null;
            set => throw null;
        }
    }
}
""";

        // https://github.com/dotnet/roslyn/issues/78829 diagnostic quality, report something better (ambiguity between X and Y)
        CreateCompilation(src).VerifyEmitDiagnostics(
