    [Fact]
    public void ObjectInitializer_01()
    {
        var src = """
var c = new C() { [0] = 1 };

static class E
{
    extension(C c)
    {
        public int this[int i] { set { System.Console.Write($"set({i}, {value}) "); } }
    }
}

class C { }
""";

        var comp = CreateCompilation(src);
        CompileAndVerify(comp, expectedOutput: "set(0, 1)").VerifyDiagnostics();
    }

    [Fact]
    public void ObjectInitializer_02()
    {
        // boxed receiver
        var src = """
var c = new S() { [0] = 1 };

static class E
{
    extension(object o)
    {
        public int this[int i] { set { System.Console.Write($"set({i}, {value}) "); } }
    }
}

struct S { }
""";

        var comp = CreateCompilation(src);
        var verifier = CompileAndVerify(comp, expectedOutput: "set(0, 1)").VerifyDiagnostics();
        verifier.VerifyIL("<top-level-statements-entry-point>", """
{
  // Code size       24 (0x18)
  .maxstack  4
  .locals init (S V_0)
  IL_0000:  ldloca.s   V_0
  IL_0002:  initobj    "S"
  IL_0008:  ldloc.0
  IL_0009:  dup
  IL_000a:  box        "S"
  IL_000f:  ldc.i4.0
  IL_0010:  ldc.i4.1
  IL_0011:  call       "void E.set_Item(object, int, int)"
  IL_0016:  pop
  IL_0017:  ret
}
""");
    }

    [Fact]
    public void ObjectInitializer_ExtensionIndexer_StructReceiver()
    {
        // sibling of ObjectInitializer_01
        // Extension indexer with by-val struct receiver, set in an object initializer.
        var src = """
class Program
{
    static void Main()
    {
        _ = new S { [GetIndex()] = GetValue() };
    }

    static int GetIndex() { System.Console.Write("idx "); return 0; }
    static int GetValue() { System.Console.Write("val "); return 5; }
}

public struct S { public int F; }

public static class E
{
    extension(S s)
    {
        public int this[int i] { set { System.Console.Write($"set:F={s.F},i={i},v={value} "); } }
    }
}
""";

        var comp = CreateCompilation(src, options: TestOptions.DebugExe);
        var verifier = CompileAndVerify(comp, expectedOutput: "idx val set:F=0,i=0,v=5 ").VerifyDiagnostics();
        verifier.VerifyIL("Program.Main", """
{
  // Code size       31 (0x1f)
  .maxstack  3
  .locals init (S V_0,
                int V_1,
                int V_2)
  IL_0000:  nop
  IL_0001:  ldloca.s   V_0
  IL_0003:  initobj    "S"
  IL_0009:  ldloc.0
  IL_000a:  call       "int Program.GetIndex()"
  IL_000f:  stloc.1
  IL_0010:  call       "int Program.GetValue()"
  IL_0015:  stloc.2
  IL_0016:  ldloc.1
  IL_0017:  ldloc.2
  IL_0018:  call       "void E.set_Item(S, int, int)"
  IL_001d:  nop
  IL_001e:  ret
}
""");
    }

