object? oNull2 = null;
oNull2[0] = new object(); // 2

object? oNotNull = new object();
oNotNull[0] = null; // 3
E.set_Item(oNotNull, 0, null); // 4

oNotNull[0] = new object();

oNotNull?[0] = null; // 5

