object? oNotNull = new object();
oNotNull[0] += (object?)null; // 1
oNotNull[0] += new object();

static class E
{
    extension<T>(T t)
    {
        public T this[int i] { get => throw null!; set => throw null!; }
        public static T operator +(T t1, T t2) => throw null!;
    }
}
