    public int Length { get { System.Console.Write($"Length(C{Counter}) "); return 5; } }
    public ref int Slice(int s, int l) { System.Console.Write($"Slice(C{Counter},{s},{l}) "); return ref Driver.Result; }
}

class Driver
{
