        }

        public int this[int i]
        {
            get { System.Console.Write($"get:{((C1)(object)x).F1} "); Program<C1>.F = new C1 { F1 = Program<C1>.F.F1 + 1 }; return 0; }
            set { System.Console.Write($"set:{((C1)(object)x).F1} "); }
        }
    }
}

class C1
{
    public int F1;
}

class Program<T>
{
    public static T F;
}

