        Test1(ref F);
        System.Console.Write($"final:{F.F1}");
    }

    static void Test1(ref S1 f)
    {
        (f[GetIndex()], int y) = GetTuple();
        System.Console.Write($"y:{y} ");
    }

    static (int, int) GetTuple() { System.Console.Write($"GetTuple:{Program.F.F1} "); Program.F.F1++; return (1, 2); }

